  ('aboriginal-a5729396-moex-00394', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列何者非屬刑法第10條第2項規定之公務員？', '["直轄市市長", "郵差", "警察", "於監獄擔任崗哨之替代役"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00395', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '警察甲於調查乙涉嫌強盜案件中，經約談目擊證人丙後，發現丙所述有刻意避重就輕並有維護乙之情形， 於是警告丙若不據實陳述，將會以丙涉嫌湮滅罪證偵辦，丙因不滿甲之言詞，而向地方檢察署提出告訴， 下列關於甲之行為是否成罪之敘述，何者正確？', '["甲成立恐嚇危害安全罪", "甲成立濫權追訴罪", "甲不成立犯罪", "甲成立犯罪，但其行為情堪憫恕得減輕其刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00396', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '身心健全的80歲爺爺與13歲孫子一起去偷隔壁鄰居的金項鍊，下列敘述何者正確？', '["兩人都應予刑罰，但都可以減輕其刑", "兩人都不應處以刑罰", "爺爺應予刑罰，但可減輕其刑，孫子不罰", "兩人都應予刑罰，但爺爺可以減輕其刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00397', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '警員甲以一行為觸犯公文書登載不實罪及對於違背職務之行為受賄罪，其中公文書登載不實罪業經發覺， 不符合自首，但甲於檢察官訊問時，除自白公文書登載不實犯行外，並就未經發覺之對於違背職務之行為 受賄罪，主動坦承犯行，並繳交犯罪所得，檢察官乃據以提起公訴。下列關於甲行為之論罪敘述，依實務 見解，何者正確？', '["依貪污治罪條例關於自首規定，減輕或免除其刑", "依貪污治罪條例關於自白規定，減輕其刑", "本件無從依自首或自白規定，減輕或免除其刑", "甲之行為應以公文書登載不實罪，但因該犯行業經發覺，故無從依自首規定，減輕其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
